// ─── assessImportRisk ────────────────────────────────────────────────

describe('assessImportRisk', () => {
  const threeModule: HeavyModule = HEAVY_MODULES.find((m) => m.name === 'three')!;
  const framerModule: HeavyModule = HEAVY_MODULES.find((m) => m.name === 'framer-motion')!;

  const makeImport = (overrides: Partial<ImportInfo> = {}): ImportInfo => ({
    filePath: 'test.tsx',
    importPath: 'three',
    lineNumber: 1,
    isDynamic: false,
    isTypeOnly: false,
    rawLine: "import * as THREE from 'three';",
    ...overrides,
  });

  it('returns critical for 3D imports in client', () => {
    expect(assessImportRisk(makeImport(), threeModule, false)).toBe('critical');
  });

  it('returns low for type-only imports', () => {
    expect(assessImportRisk(makeImport({ isTypeOnly: true }), threeModule, false)).toBe('low');
  });

  it('returns low for dynamic imports', () => {
    expect(assessImportRisk(makeImport({ isDynamic: true }), threeModule, false)).toBe('low');
  });

  it('returns low for non-dynamic-required modules', () => {
    expect(assessImportRisk(makeImport({ importPath: 'framer-motion' }), framerModule, false)).toBe('low');
  });
});

// ─── analyzeFileImports ──────────────────────────────────────────────

describe('analyzeFileImports', () => {
  it('flags static three import', () => {
    const content = `import * as THREE from 'three';
export function MyScene() { return <mesh />; }`;
    const issues = analyzeFileImports(content, 'src/components/Scene.tsx');
    expect(issues.length).toBeGreaterThan(0);
    expect(issues[0].risk).toBe('critical');
  });

  it('ignores dynamic three import', () => {
    const content = `const THREE = await import('three');`;
    const issues = analyzeFileImports(content, 'src/components/Scene.tsx');
    expect(issues).toHaveLength(0);
  });

  it('ignores relative imports', () => {
    const content = `import { helper } from './utils';
import { config } from '@/lib/config';`;
    const issues = analyzeFileImports(content, 'src/components/App.tsx');
    expect(issues).toHaveLength(0);
  });

  it('ignores type imports', () => {
    const content = `import type { Scene } from 'three';`;
    const issues = analyzeFileImports(content, 'src/components/Scene.tsx');
    expect(issues).toHaveLength(0);
  });
});

