// ─── detectBarrelExports ─────────────────────────────────────────────

describe('detectBarrelExports', () => {
  it('detects barrel with many re-exports', () => {
    const content = `export * from './a';
export * from './b';
export * from './c';
export * from './d';
export * from './e';
export * from './f';`;
    const result = detectBarrelExports(content, 'src/lib/utils/index.ts');
    expect(result).not.toBeNull();
    expect(result?.exportCount).toBe(6);
  });

  it('ignores non-index files', () => {
    const content = `export * from './a';
export * from './b';
export * from './c';
export * from './d';
export * from './e';`;
    const result = detectBarrelExports(content, 'src/lib/utils/helpers.ts');
    expect(result).toBeNull();
  });

  it('ignores small barrels', () => {
    const content = `export * from './a';
export * from './b';`;
    const result = detectBarrelExports(content, 'src/lib/index.ts');
    expect(result).toBeNull();
  });

  it('counts named re-exports', () => {
    const content = `export { a } from './a';
export { b, c } from './b';
export { d } from './d';
export { e } from './e';
export { f } from './f';`;
    const result = detectBarrelExports(content, 'src/lib/index.ts');
    expect(result).not.toBeNull();
    expect(result?.exportCount).toBe(5);
  });
});

// ─── generateBundleReport ────────────────────────────────────────────

describe('generateBundleReport', () => {
  it('generates a valid report', () => {
    const files = [
      { path: 'src/components/Scene.tsx', content: `import * as THREE from 'three';` },
      { path: 'src/components/Button.tsx', content: `import React from 'react';` },
    ];
    const report = generateBundleReport(files);
    expect(report.totalFilesScanned).toBe(2);
    expect(report.totalImports).toBe(2);
    expect(report.issues.length).toBeGreaterThan(0);
    expect(report.summary.criticalCount).toBeGreaterThan(0);
  });

  it('returns clean report for safe imports', () => {
    const files = [
      { path: 'src/components/Button.tsx', content: `import React from 'react';` },
      { path: 'src/components/Link.tsx', content: `import Link from 'next/link';` },
    ];
    const report = generateBundleReport(files);
    expect(report.issues).toHaveLength(0);
  });

  it('sorts issues by risk', () => {
    const files = [
      { path: 'src/a.tsx', content: `import * as THREE from 'three';` },
      { path: 'src/b.tsx', content: `import { Canvas } from 'konva';` },
    ];
    const report = generateBundleReport(files);
    if (report.issues.length >= 2) {
      const riskOrder = { critical: 0, high: 1, medium: 2, low: 3 };
      for (let j = 1; j < report.issues.length; j++) {
        expect(riskOrder[report.issues[j].risk]).toBeGreaterThanOrEqual(
          riskOrder[report.issues[j - 1].risk]
        );
      }
    }
  });

  it('detects barrel exports', () => {
    const barrelContent = Array.from({ length: 6 }, (_, i) => `export * from './m${i}';`).join('\n');
    const files = [
      { path: 'src/lib/index.ts', content: barrelContent },
    ];
    const report = generateBundleReport(files);
    expect(report.barrelIssues).toHaveLength(1);
  });
});

// ─── generateRecommendations ─────────────────────────────────────────

describe('generateRecommendations', () => {
  it('recommends dynamic imports for critical', () => {
    const summary: BundleSummary = {
      criticalCount: 2, highCount: 0, mediumCount: 0, lowCount: 0,
      totalEstimatedWasteKb: 600, heavyModulesFound: ['three'],
      dynamicImportCandidates: 2, barrelExportIssues: 0,
    };
    const issues: BundleIssue[] = [
      { risk: 'critical', category: '3D', filePath: 'a.tsx', importPath: 'three', lineNumber: 1, message: '', suggestion: '', estimatedSizeKb: 600 },
    ];
    const recs = generateRecommendations(summary, issues, []);
    expect(recs.some((r) => r.includes('CRITICAL'))).toBe(true);
  });

  it('gives all-clear for clean codebase', () => {
    const summary: BundleSummary = {
      criticalCount: 0, highCount: 0, mediumCount: 0, lowCount: 0,
      totalEstimatedWasteKb: 0, heavyModulesFound: [],
      dynamicImportCandidates: 0, barrelExportIssues: 0,
    };
    const recs = generateRecommendations(summary, [], []);
    expect(recs.some((r) => r.includes('No significant'))).toBe(true);
  });

  it('mentions barrel exports', () => {
    const summary: BundleSummary = {
      criticalCount: 0, highCount: 0, mediumCount: 0, lowCount: 0,
      totalEstimatedWasteKb: 0, heavyModulesFound: [],
      dynamicImportCandidates: 0, barrelExportIssues: 3,
    };
    const barrels: BarrelExportIssue[] = [
      { filePath: 'index.ts', exportCount: 10, reExportPaths: [], message: 'test' },
    ];
    const recs = generateRecommendations(summary, [], barrels);
    expect(recs.some((r) => r.includes('barrel'))).toBe(true);
  });
});

// ─── formatBundleReportText ──────────────────────────────────────────

describe('formatBundleReportText', () => {
  it('generates readable text', () => {
    const report = generateBundleReport([
      { path: 'test.tsx', content: `import React from 'react';` },
    ]);
    const text = formatBundleReportText(report);
    expect(text).toContain('BUNDLE ANALYSIS REPORT');
    expect(text).toContain('SUMMARY');
    expect(text).toContain('RECOMMENDATIONS');
  });

  it('includes issues section when there are issues', () => {
    const report = generateBundleReport([
      { path: 'test.tsx', content: `import * as THREE from 'three';` },
    ]);
    const text = formatBundleReportText(report);
    expect(text).toContain('IMPORT ISSUES');
  });
});

// ─── HEAVY_MODULES Registry ─────────────────────────────────────────

describe('HEAVY_MODULES', () => {
  it('has entries for all major heavy modules', () => {
    const names = HEAVY_MODULES.map((m) => m.name);
    expect(names).toContain('three');
    expect(names).toContain('konva');
    expect(names).toContain('recharts');
    expect(names).toContain('remotion');
  });

  it('all entries have required fields', () => {
    for (const m of HEAVY_MODULES) {
      expect(m.name).toBeTruthy();
      expect(m.pattern).toBeInstanceOf(RegExp);
      expect(m.estimatedSizeKb).toBeGreaterThan(0);
      expect(m.category).toBeTruthy();
      expect(typeof m.shouldBeDynamic).toBe('boolean');
    }
  });

  it('patterns match expected import paths', () => {
    // Each module's pattern should match at least one realistic import path
    const testPaths: Record<string, string> = {
      'three': 'three',
      '@react-three/fiber': '@react-three/fiber',
      '@react-three/drei': '@react-three/drei',
      'konva': 'konva',
      'fabric': 'fabric',
      'recharts': 'recharts',
      'monaco-editor': 'monaco-editor',
      'framer-motion': 'framer-motion',
      'lodash': 'lodash',
      'd3': 'd3',
      'pdfjs-dist': 'pdfjs-dist',
      'xlsx': 'xlsx',
      'ffmpeg': '@ffmpeg/ffmpeg',
      'sharp': 'sharp',
      'remotion': 'remotion',
      'codemirror': 'codemirror',
      'highlight.js': 'highlight.js',
      'prismjs': 'prismjs',
      'chart.js': 'chart.js',
    };
    for (const m of HEAVY_MODULES) {
      const path = testPaths[m.name];
      expect(m.pattern.test(path)).toBe(true);
    }
  });
});
